      emitter.emit("multi", "a", "b", "c");

      expect(fn).toHaveBeenCalledWith("a", "b", "c");
    });

    it("should call listener on every emit", () => {
      const emitter = new EventEmitter();
      const fn = vi.fn();

      emitter.on("ping", fn);
      emitter.emit("ping");
      emitter.emit("ping");
      emitter.emit("ping");

      expect(fn).toHaveBeenCalledTimes(3);
    });
  });

